const timezone = 'America/Sao_Paulo';
const yesOption = $env.N8N_POLL_YES_OPTION || 'Eu peguei';
const noOption = $env.N8N_POLL_NO_OPTION || 'Nao peguei';
const session = $env.N8N_WAHA_SESSION || 'default';
const chatId = $env.N8N_WA_GROUP_ID;
if (!chatId || chatId.includes('preencher')) {
  throw new Error('Configure N8N_WA_GROUP_ID com o ID do grupo do WhatsApp antes de ativar o workflow.');
}
const parts = new Intl.DateTimeFormat('pt-BR', {
  timeZone: timezone,
  year: 'numeric',
  month: '2-digit',
  day: '2-digit'
}).formatToParts(new Date()).reduce((acc, part) => {
  acc[part.type] = part.value;
  return acc;
}, {});
const dateKey = `${parts.year}-${parts.month}-${parts.day}`;
const dateLabel = `${parts.day}/${parts.month}`;
const clientMessageId = `almoco_${parts.year}${parts.month}${parts.day}_${Math.random().toString(36).slice(2, 8)}`;
const data = $getWorkflowStaticData('global');
data.lunchPolls = data.lunchPolls || {};
data.activeLunchPollDateKey = dateKey;
data.lunchPolls[dateKey] = {
  dateKey,
  dateLabel,
  clientMessageId,
  pollId: null,
  chatId,
  session,
  yesOption,
  noOption,
  status: 'prepared',
  votes: {},
  voteFailures: [],
  sentAt: new Date().toISOString()
};
return [{
  json: {
    dateKey,
    dateLabel,
    clientMessageId,
    pollRequest: {
      session,
      chatId,
      id: clientMessageId,
      poll: {
        name: `Quem pegou almoço hoje? (${dateLabel})`,
        options: [yesOption, noOption],
        multipleAnswers: false
      }
    }
  }
}];

const data = $getWorkflowStaticData('global');
const dateKey = data.activeLunchPollDateKey;
const poll = dateKey && data.lunchPolls ? data.lunchPolls[dateKey] : null;
const response = $input.first()?.json || {};
const pollId = response.id || response.messageId || response.message?.id || response.key?.id || response._data?.id || poll?.clientMessageId;
if (poll) {
  poll.pollId = pollId;
  poll.status = 'sent';
  poll.wahaResponse = response;
  poll.updatedAt = new Date().toISOString();
}
return [{ json: { ok: true, dateKey, pollId, response } }];

function parseJsonEnv(name, fallback) {
  try {
    const raw = $env[name];
    return raw ? JSON.parse(raw) : fallback;
  } catch (error) {
    return fallback;
  }
}
function normalizeId(value) {
  return String(value || '').replace(/@(c\.us|s\.whatsapp\.net|lid)$/i, '');
}
const body = $json.body || $json;
const event = body.event;
const payload = body.payload || {};
const vote = payload.vote || payload;
const pollMeta = payload.poll || {};
const data = $getWorkflowStaticData('global');
data.lunchPolls = data.lunchPolls || {};
if (!['poll.vote', 'poll.vote.failed'].includes(event)) {
  return [{ json: { ok: true, ignored: true, reason: `Evento ignorado: ${event || 'sem event'}` } }];
}
const incomingPollId = pollMeta.id || vote.pollMessageId || vote.pollId;
const polls = Object.values(data.lunchPolls);
let poll = polls.find((item) => incomingPollId && (item.pollId === incomingPollId || incomingPollId.includes(item.clientMessageId)));
if (!poll && data.activeLunchPollDateKey) {
  const active = data.lunchPolls[data.activeLunchPollDateKey];
  const sameChat = active && (vote.to === active.chatId || pollMeta.to === active.chatId);
  if (sameChat && pollMeta.fromMe !== false) poll = active;
}
if (!poll) {
  return [{ json: { ok: true, ignored: true, reason: 'Voto nao pertence a enquete ativa conhecida', incomingPollId } }];
}
const voterId = vote.from || vote.participant || payload.participant || payload.from;
if (!voterId) {
  return [{ json: { ok: false, ignored: true, reason: 'Evento poll.vote sem identificacao do votante', payload } }];
}
const timestamp = Number(vote.timestamp || body.timestamp || Math.floor(Date.now() / 1000));
const contactMap = parseJsonEnv('N8N_CONTACT_NAME_MAP', {});
const phone = normalizeId(voterId);
const name = contactMap[voterId] || contactMap[phone] || vote.name || vote.pushName || vote.notifyName || payload.contact?.name || phone || voterId;
const selectedOptions = Array.isArray(vote.selectedOptions) ? vote.selectedOptions : [];
poll.votes = poll.votes || {};
poll.voteFailures = poll.voteFailures || [];
if (event === 'poll.vote.failed') {
  poll.voteFailures.push({ voterId, name, timestamp, raw: body });
  poll.updatedAt = new Date().toISOString();
  return [{ json: { ok: true, failedVoteStored: true, voterId, name, dateKey: poll.dateKey } }];
}
const previous = poll.votes[voterId];
if (!previous || timestamp >= Number(previous.timestamp || 0)) {
  poll.votes[voterId] = { voterId, name, selectedOptions, timestamp, raw: body };
}
poll.updatedAt = new Date().toISOString();
return [{ json: { ok: true, stored: true, dateKey: poll.dateKey, voterId, name, selectedOptions } }];

function parseJsonEnv(name, fallback) {
  try {
    const raw = $env[name];
    return raw ? JSON.parse(raw) : fallback;
  } catch (error) {
    return fallback;
  }
}
function dayParts() {
  return new Intl.DateTimeFormat('pt-BR', {
    timeZone: 'America/Sao_Paulo',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit'
  }).formatToParts(new Date()).reduce((acc, part) => {
    acc[part.type] = part.value;
    return acc;
  }, {});
}
function normalizeId(value) {
  return String(value || '').replace(/@(c\.us|s\.whatsapp\.net|lid)$/i, '');
}
const data = $getWorkflowStaticData('global');
const parts = dayParts();
const todayKey = `${parts.year}-${parts.month}-${parts.day}`;
const fallbackKey = data.activeLunchPollDateKey;
const poll = data.lunchPolls?.[todayKey] || data.lunchPolls?.[fallbackKey];
const session = $env.N8N_WAHA_SESSION || 'default';
const managerChatId = $env.N8N_MANAGER_CHAT_ID;
if (!managerChatId || managerChatId.includes('preencher')) {
  throw new Error('Configure N8N_MANAGER_CHAT_ID com o WhatsApp da gestora antes de ativar o workflow.');
}
if (!poll) {
  const text = `🍽️ *Almoço de hoje (${parts.day}/${parts.month})*\n\nNao encontrei enquete ativa salva para hoje. Verifique se o fluxo das 11h rodou e se o WAHA estava conectado.`;
  return [{ json: { messageRequest: { session, chatId: managerChatId, text }, summary: { foundPoll: false } } }];
}
const yesOption = poll.yesOption || $env.N8N_POLL_YES_OPTION || 'Eu peguei';
const votes = Object.values(poll.votes || {});
const confirmed = votes
  .filter((vote) => Array.isArray(vote.selectedOptions) && vote.selectedOptions.includes(yesOption))
  .sort((a, b) => String(a.name || a.voterId).localeCompare(String(b.name || b.voterId), 'pt-BR'));
const contactMap = parseJsonEnv('N8N_CONTACT_NAME_MAP', {});
const expectedRaw = parseJsonEnv('N8N_EXPECTED_PARTICIPANTS', []);
const expected = Array.isArray(expectedRaw) ? expectedRaw.map((entry) => {
  if (typeof entry === 'string') return { id: entry, name: contactMap[entry] || contactMap[normalizeId(entry)] || normalizeId(entry) };
  return { id: entry.id, name: entry.name || contactMap[entry.id] || contactMap[normalizeId(entry.id)] || normalizeId(entry.id) };
}).filter((entry) => entry.id) : [];
const respondedIds = new Set(votes.map((vote) => vote.voterId));
const missing = expected.filter((entry) => !respondedIds.has(entry.id));
const failed = poll.voteFailures || [];
const header = `🍽️ *Almoço de hoje (${poll.dateLabel || `${parts.day}/${parts.month}`})*`;
const confirmedText = confirmed.length
  ? confirmed.map((vote) => `• ${vote.name || normalizeId(vote.voterId)}`).join('\n')
  : 'Nenhuma pessoa confirmou almoço na enquete.';
const missingText = missing.length
  ? `\n\nSem resposta na lista esperada (${missing.length}):\n${missing.map((entry) => `• ${entry.name}`).join('\n')}\n\nFavor confirmar manualmente com essas pessoas antes do lançamento.`
  : '\n\nLista de participantes esperados nao configurada; confira manualmente se alguem esqueceu de responder.';
const failedText = failed.length
  ? `\n\nAtenção: ${failed.length} voto(s) chegaram como poll.vote.failed no WAHA. Confira manualmente no grupo.`
  : '';
const text = `${header}\n\nConfirmaram almoço (${confirmed.length}):\n${confirmedText}${missingText}${failedText}`;
return [{
  json: {
    messageRequest: { session, chatId: managerChatId, text },
    summary: {
      dateKey: poll.dateKey,
      pollId: poll.pollId,
      confirmedCount: confirmed.length,
      missingCount: missing.length,
      failedCount: failed.length
    }
  }
}];

const error = $json;
console.error('Erro no workflow de enquete de almoco:', JSON.stringify(error, null, 2));
return [{ json: { logged: true, error } }];
